    packages: ITINERARIES_DATABASE.filter(p => p.destinations.some(d => d.includes("Saigon") || d.includes("Phu Quoc") || d.includes("Mekong") || d.includes("Vung Tau") || d.includes("Con Dao") || d.includes("Mui Ne")))
